#include <iostream>
using namespace std;

class Employee {
private:
    int salary;
public:
    void setSalary(int s) {
        salary = s;
    }
    int getSalary() {
        return salary;
    }
};

int main() {
    Employee emp;
    emp.setSalary(50000);
    cout << "Salary: " << emp.getSalary() << endl;
    return 0;
}

