    Box b;
    b.display();
    return 0;
}

#include <iostream>
using namespace std;

class Counter {
public:
    static int count;
    Counter() {
        count++;
    }
};

int Counter::count = 0; // Initialize static member

int main() {
    Counter c1;
    Counter c2;
    cout << "Count: " << Counter::count << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Example {
    int x;
public:
    void setX(int x) {
        this->x = x; // this->x refers to member, x refers to param
    }
    void print() { cout << x << endl; }
};

int main() {
    Example e;
    e.setX(42);
    e.print();
    return 0;
}

#include <iostream>
using namespace std;

class Point {
public:
    int x, y;
    Point(int a, int b) : x(a), y(b) {}

    // Copy Constructor
    Point(const Point &p) {
        x = p.x;
        y = p.y;
        cout << "Copied!" << endl;
    }
};

int main() {
    Point p1(10, 20);
    Point p2 = p1; // Calls copy constructor
    return 0;
}
